import { Link } from 'react-router-dom';

export default function NotFound() {
  return (
    <div className="page page-enter" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ textAlign: 'center', padding: '60px 20px' }}>
        <div style={{ fontFamily: 'var(--font-mono)', fontSize: 80, color: 'var(--clr-accent)', lineHeight: 1 }}>404</div>
        <h2 style={{ fontSize: 28, marginTop: 16, marginBottom: 12 }}>Page Not Found</h2>
        <p style={{ color: 'var(--clr-text-dim)', marginBottom: 28 }}>
          This page doesn't exist. Check the URL or go back home.
        </p>
        <Link to="/" className="btn btn-primary">← Back to Home</Link>
      </div>
    </div>
  );
}
